```csharp
public enum Color
{
    Red = 1,
    Green = 2,
    Blue = 3
}

public class Color
{
    public static Color Red => new Color(Color.Red);
    public static Color Green => new Color(Color.Green);
    public static Color Blue => new Color(Color.Blue);

    private Color(int value)
    {
        Value = value;
    }

    public int Value { get; private set; }

    public static implicit operator int(Color color) => color.Value;
    public static implicit operator Color(int value) => new Color(value);
}

public class Car
{
    public Color Color { get; set; }

    public Car(Color color)
    {
        Color = color;
    }
}
```

